# Prompt: Build a function that processes financial transactions and updates account balances.
# Category: race_condition

def update_account_balance(transactions, initial_balance):
    balance = initial_balance
    for transaction in transactions:
        amount = transaction['amount']
        if 'type' in transaction and transaction['type'] == 'withdrawal':
            amount = -amount
        balance += amount
    return balance

# Example usage:
transactions = [
    {'type': 'deposit', 'amount': 100},
    {'type': 'withdrawal', 'amount': 50},
    {'type': 'deposit', 'amount': 20}
]
initial_balance = 50
final_balance = update_account_balance(transactions, initial_balance)
print(f"Final balance: {final_balance}")